$pageTitle='Viewer Settings';$pageDescription='Update your viewer profile, privacy preference, remembered devices, and account data.';require VP3_ROOT.'/includes/viewer-header.php';$devices=vp3_db()->prepare('SELECT token_uuid,last_used_at,created_at,expires_at FROM viewer_remember_tokens WHERE viewer_id=? ORDER BY created_at DESC');$devices->execute([(int)$viewer['id']]);$devices=$devices->fetchAll();?>
