<section class="card viewer-settings-card"><h2>Remembered devices</h2><p><?=count($devices)?> remembered sign-in<?=count($devices)===1?'':'s'?>. Current browser sessions remain active until sign-out.</p><form method="post"><?=vp3_csrf_field()?><input type="hidden" name="action" value="revoke_devices"><button class="button secondary">Sign out remembered devices</button></form></section>
